import os
import sys
import zipfile
import tarfile

def backup_directory(directory_path, compression_format):
    if not os.path.isdir(directory_path):
        print(f"Error: {directory_path} is not a valid directory.")
        sys.exit(1)

    base_name = os.path.basename(directory_path)
    archive_name = f"{base_name}.{compression_format}"

    try:
        if compression_format == 'tar.gz':
            with tarfile.open(archive_name, "w:gz") as tar:
                tar.add(directory_path, arcname=base_name)
        elif compression_format == 'tar.bz2':
            with tarfile.open(archive_name, "w:bz2") as tar:
                tar.add(directory_path, arcname=base_name)
        elif compression_format == 'zip':
            with zipfile.ZipFile(archive_name, 'w', zipfile.ZIP_DEFLATED) as zipf:
                for root, dirs, files in os.walk(directory_path):
                    for file in files:
                        file_path = os.path.join(root, file)
                        arcname = os.path.relpath(file_path, start=directory_path)
                        zipf.write(file_path, arcname=arcname)
        elif compression_format == '7z':
            try:
                import py7zr
                with py7zr.SevenZipFile(archive_name, mode='w') as z:
                    z.writeall(directory_path, base_name)
            except ImportError:
                print("Error: 7z compression requires the py7zr library. Please install it using pip.")
                sys.exit(1)
        else:
            print(f"Error: Unsupported compression format {compression_format}.")
            sys.exit(1)

        print(f"Backup successful: {archive_name}")
    except Exception as e:
        print(f"Error: Failed to create backup - {e}")
        sys.exit(1)

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: python backup.py <directory_path> <compression_format>")
        sys.exit(1)

    directory_path = sys.argv[1]
    compression_format = sys.argv[2]

    backup_directory(directory_path, compression_format)